#!/usr/bin/env bash
# SPDX-License-Identifier: MPL-2.0
# TLC run script for CapabilityToken — generated by tlaiser
# https://github.com/hyperpolymath/tlaiser
#
# Prerequisites:
#   - Java runtime (>= 11)
#   - tla2tools.jar on CLASSPATH or in current directory
#   - Or: install Community TLA+ Toolbox

set -euo pipefail

# Locate TLA+ tools
TLA2TOOLS="${TLA2TOOLS:-tla2tools.jar}"
if [[ ! -f "$TLA2TOOLS" ]]; then
    echo "Error: tla2tools.jar not found. Set TLA2TOOLS env var or download from:"
    echo "  https://github.com/tlaplus/tlaplus/releases"
    exit 1
fi

echo "Running TLC on CapabilityToken.tla ..."
java -XX:+UseParallelGC -Xmx4g -jar "$TLA2TOOLS" -workers 4 -config CapabilityToken.cfg CapabilityToken.tla

echo "TLC completed."
